@namespace Lumeo
@typeparam TItem
@implements IAsyncDisposable

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium text-foreground mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<div class="@ContainerClass" @onclick="FocusInput" @attributes="AdditionalAttributes">
    @if (Tags is { Count: > 0 })
    {
        @foreach (var (tag, index) in Tags.Select((t, i) => (t, i)))
        {
            // @key combines the value with its position so that duplicate tags
            // (AllowDuplicates=true) get distinct keys — keying by `tag` alone
            // throws on render when two equal values share a key. Removal goes
            // through RemoveTagAt(index) so clicking one chip's X removes only
            // that occurrence, not every value-equal tag.
            if (TagTemplate is not null)
            {
                <div class="inline-flex items-center" @key="(tag, index)">
                    @TagTemplate(tag)
                    @if (!Disabled)
                    {
                        <button type="button" class="ms-1 rounded-[calc(var(--radius)*2)] hover:bg-foreground/20 focus:outline-none" aria-label="@($"Remove {GetTagTextSafe(tag)}")" @onclick="() => RemoveTagAt(index)" @onclick:stopPropagation="true">
                            <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3 w-3" />
                        </button>
                    }
                </div>
            }
            else
            {
                <span class="inline-flex items-center gap-1 rounded-md border border-border/40 bg-secondary px-2 py-0.5 text-xs font-medium text-secondary-foreground" @key="(tag, index)">
                    @GetTagTextSafe(tag)
                    @if (!Disabled)
                    {
                        <button type="button" class="rounded-[calc(var(--radius)*2)] hover:bg-foreground/20 focus:outline-none" aria-label="@($"Remove {GetTagTextSafe(tag)}")" @onclick="() => RemoveTagAt(index)" @onclick:stopPropagation="true">
                            <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3 w-3" />
                        </button>
                    }
                </span>
            }
        }
    }

    <div class="relative flex-1 min-w-[80px]">
        <input id="@EffectiveId"
               type="text"
               role="combobox"
               class="w-full bg-transparent text-sm outline-none placeholder:text-muted-foreground disabled:cursor-not-allowed"
               placeholder="@(Tags is { Count: > 0 } ? "" : (Placeholder ?? L["TagInput.Placeholder"]))"
               value="@_inputValue"
               name="@(Name ?? FormField?.Name)"
               aria-required="@(Required ? "true" : "false")"
               aria-invalid="@(EffectiveInvalid ? "true" : "false")"
               aria-autocomplete="list"
               aria-haspopup="listbox"
               aria-expanded="@(_showSuggestions && FilteredSuggestions.Count > 0 ? "true" : "false")"
               aria-controls="@_suggestionsId"
               aria-activedescendant="@ActiveDescendantId"
               aria-describedby="@FormFieldDescribedBy"
               @oninput="OnInput"
               @onkeydown="OnKeyDown"
               @onfocus="() => _showSuggestions = FilteredSuggestions.Count > 0"
               disabled="@(IsAtMax || Disabled)"
               autocomplete="off" />

        @if (_showSuggestions && FilteredSuggestions.Count > 0)
        {
            <div id="@_suggestionsId" role="listbox" class="fixed z-50 min-w-[150px] overflow-hidden rounded-md border border-border/40 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in">
                @foreach (var (suggestion, index) in FilteredSuggestions.Select((s, i) => (s, i)))
                {
                    var isActive = index == _activeSuggestion;
                    <button type="button"
                            id="@OptionId(index)"
                            role="option"
                            aria-selected="@(isActive ? "true" : "false")"
                            class="@($"flex w-full items-center rounded-sm px-2 py-1.5 text-sm focus:outline-none cursor-pointer transition-colors {(isActive ? "bg-accent text-accent-foreground" : "hover:bg-accent hover:text-accent-foreground")}")"
                            @onmouseenter="() => _activeSuggestion = index"
                            @onclick="() => SelectSuggestion(suggestion)">
                        @if (SuggestionTemplate is not null)
                        {
                            @SuggestionTemplate(suggestion)
                        }
                        else
                        {
                            @GetSuggestionTextSafe(suggestion)
                        }
                    </button>
                }
            </div>
        }
    </div>
</div>

@if (!InsideFormField)
{
    @if (_validationError is not null)
    {
        <p class="text-xs text-destructive mt-1.5">@_validationError</p>
    }
    else if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive mt-1.5">@ErrorText</p>
    }
    else if (IsAtMax && (MaxTagsHelperText is not null || MaxTags > 0))
    {
        <p class="text-xs text-muted-foreground mt-1.5">@(MaxTagsHelperText ?? L["TagInput.MaxTagsReached"])</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground mt-1.5">@HelperText</p>
    }
}
</div>

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    // aria-describedby on the input announces the FormField help/error to a screen
    // reader.
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Adopt the FormField's generated id so the field's <label for> resolves to the
    // inner text <input> the user types into (Base UI Field a11y), mirroring
    // Input/Switch/Textarea/DatePicker. Null outside a FormField; empty guard avoids
    // id="" if no id was generated. EffectiveId is the DOM id actually rendered, so
    // all focus/popover/prevent-default interop must target it (not the raw _inputId).
    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;
    private string EffectiveId => FormFieldControlId ?? _inputId;

    /// <summary>The committed tags, rendered as removable chips before the text input.
    /// Two-way bindable via <see cref="TagsChanged"/>.</summary>
    [Parameter] public List<TItem>? Tags { get; set; }
    /// <summary>Raised whenever a tag is added or removed, with the full updated list.</summary>
    [Parameter] public EventCallback<List<TItem>> TagsChanged { get; set; }
    /// <summary>Maximum number of tags allowed. <c>0</c> (default) means unlimited; once
    /// reached, the input disables and <see cref="MaxTagsHelperText"/> shows.</summary>
    [Parameter] public int MaxTags { get; set; }
    /// <summary>Allows the same value to be added more than once (by default, a
    /// duplicate add and duplicate suggestions are suppressed).</summary>
    [Parameter] public bool AllowDuplicates { get; set; }
    /// <summary>Placeholder shown in the text input while no tags are present. Falls
    /// back to the localized "TagInput.Placeholder" string when null; hidden once at
    /// least one tag exists.</summary>
    [Parameter] public string? Placeholder { get; set; }
    /// <summary>Disables the input and hides each chip's remove button.</summary>
    [Parameter] public bool Disabled { get; set; }
    /// <summary>Candidate values shown in the autocomplete dropdown as the user types,
    /// filtered to those matching the current input text and (unless
    /// <see cref="AllowDuplicates"/>) not already tagged.</summary>
    [Parameter] public List<TItem>? Suggestions { get; set; }
    /// <summary>Marks the field required, rendering a trailing asterisk on <see cref="Label"/>
    /// and setting <c>aria-required</c> on the text input.</summary>
    [Parameter] public bool Required { get; set; }
    /// <summary>Forces the invalid (error) visual state — a destructive border/ring — even
    /// when not inside a <c>FormField</c> reporting an error. ORed with the ambient
    /// <c>FormField</c> error state and any live <see cref="ValidateInput"/>/
    /// <see cref="ValidateInputAsync"/> failure.</summary>
    [Parameter] public bool Invalid { get; set; }
    /// <summary>Error message shown below the field when invalid (and no live validation
    /// error is active). Only rendered when this input is standalone (outside a
    /// <c>FormField</c>, which owns its own error slot).</summary>
    [Parameter] public string? ErrorText { get; set; }
    /// <summary>Helper text shown below the field when not invalid and not at the
    /// <see cref="MaxTags"/> limit. Only rendered when this input is standalone (outside
    /// a <c>FormField</c>).</summary>
    [Parameter] public string? HelperText { get; set; }
    /// <summary>Field label rendered above the input. Suppressed when nested inside a
    /// <c>FormField</c>, which renders its own label.</summary>
    [Parameter] public string? Label { get; set; }
    /// <summary>The text input's <c>name</c> attribute. Falls back to the ambient
    /// <c>FormField</c>'s name when null.</summary>
    [Parameter] public string? Name { get; set; }
    /// <summary>Additional CSS classes merged onto the field's container <c>div</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Focuses the inner text &lt;input&gt; on first render. See
    /// <c>Input.AutoFocus</c> for why the HTML <c>autofocus</c> attribute
    /// doesn't work in Blazor WASM.</summary>
    [Parameter] public bool AutoFocus { get; set; }
    /// <summary>Message shown once <see cref="MaxTags"/> is reached (in place of
    /// <see cref="HelperText"/>). Falls back to the localized "TagInput.MaxTagsReached"
    /// string when null.</summary>
    [Parameter] public string? MaxTagsHelperText { get; set; }

    /// <summary>Converts a tag to its display text on a chip. Falls back to
    /// <c>item?.ToString()</c> when null — required for a non-<c>string</c> <c>TItem</c>
    /// to render sensibly.</summary>
    [Parameter] public Func<TItem, string>? GetTagText { get; set; }
    /// <summary>Converts a candidate to its display text in the suggestions dropdown.
    /// Falls back to <see cref="GetTagText"/>, then <c>item?.ToString()</c>.</summary>
    [Parameter] public Func<TItem, string>? GetSuggestionText { get; set; }
    /// <summary>Custom render fragment for a chip's content, replacing the default
    /// text span (the remove button still renders alongside it).</summary>
    [Parameter] public RenderFragment<TItem>? TagTemplate { get; set; }
    /// <summary>Custom render fragment for a suggestion row's content, replacing
    /// <see cref="GetSuggestionText"/>.</summary>
    [Parameter] public RenderFragment<TItem>? SuggestionTemplate { get; set; }
    /// <summary>Characters that, when typed or pasted, split the current input into
    /// separate tags (each trimmed segment is added via <see cref="CreateTag"/> or, for
    /// <c>TItem</c> = <c>string</c>, used as-is). Defaults to <c>[","]</c>.</summary>
    [Parameter] public string[] Separators { get; set; } = new[] { "," };
    /// <summary>Synchronous validator run against free-text input before it becomes a
    /// tag. Returning a non-null string rejects the input and shows it as the field's
    /// error message. Run before <see cref="ValidateInputAsync"/>.</summary>
    [Parameter] public Func<string, string?>? ValidateInput { get; set; }
    /// <summary>Asynchronous validator run after <see cref="ValidateInput"/> passes.
    /// Returning a non-null string rejects the input and shows it as the field's error
    /// message.</summary>
    [Parameter] public Func<string, Task<string?>>? ValidateInputAsync { get; set; }
    /// <summary>Converts validated free text into a <typeparamref name="TItem"/>.
    /// Required when <typeparamref name="TItem"/> is not <c>string</c> — otherwise
    /// free-text entry throws. Return <c>null</c> to silently discard the input.</summary>
    [Parameter] public Func<string, TItem?>? CreateTag { get; set; }

    /// <summary>Unmatched attributes splatted onto the field's container <c>div</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true || _validationError is not null;
    private bool InsideFormField => FormField is not null;

    private string _inputValue = "";
    private bool _showSuggestions;
    private string? _validationError;
    // Index of the keyboard-highlighted suggestion, or -1 when none is active.
    // Drives aria-activedescendant + the active-row highlight; Enter commits it.
    private int _activeSuggestion = -1;
    private readonly string _inputId = LumeoIds.New("taginput");

    private string OptionId(int index) => $"{_suggestionsId}-opt{index}";

    private string? ActiveDescendantId =>
        _showSuggestions && _activeSuggestion >= 0 && _activeSuggestion < FilteredSuggestions.Count
            ? OptionId(_activeSuggestion)
            : null;

    /// <summary>Programmatically move focus to the inner text input.</summary>
    public ValueTask FocusAsync() => Interop.FocusElement(EffectiveId);
    private readonly string _suggestionsId = LumeoIds.New("taginput-suggestions");
    private bool _suggestionsRegistered;

    private bool IsAtMax => MaxTags > 0 && (Tags?.Count ?? 0) >= MaxTags;

    private string ContainerClass => Cx.Merge("flex flex-wrap items-center gap-1.5 min-h-9 w-full rounded-md border", (EffectiveInvalid ? "border-destructive focus-within:ring-destructive/20" : "border-input focus-within:ring-ring"), "bg-transparent px-3 py-1.5 text-sm transition-colors focus-within:ring-[1.5px]", (Disabled ? "cursor-not-allowed opacity-50" : "cursor-text"), Class);

    private string GetTagTextSafe(TItem item)
        => GetTagText is not null ? GetTagText(item) : (item?.ToString() ?? "");

    private string GetSuggestionTextSafe(TItem item)
        => GetSuggestionText is not null ? GetSuggestionText(item)
            : GetTagText is not null ? GetTagText(item)
            : (item?.ToString() ?? "");

    // Memoised filter list. Recomputed when any of (Suggestions ref,
    // Tags ref, _inputValue, AllowDuplicates) changes. Property getter
    // previously recomputed on every access — focus / blur / render
    // each touched FilteredSuggestions multiple times so the LINQ ran
    // ~3-5× per keystroke against the full Suggestions list. Cache
    // collapses that to one recompute per actual input change.
    private List<TItem> _filteredSuggestionsCache = [];
    private object? _filterCacheSuggestionsRef;
    private object? _filterCacheTagsRef;
    private string? _filterCacheInputValue;
    private bool _filterCacheAllowDup;

    private List<TItem> FilteredSuggestions
    {
        get
        {
            if (ReferenceEquals(_filterCacheSuggestionsRef, Suggestions)
                && ReferenceEquals(_filterCacheTagsRef, Tags)
                && string.Equals(_filterCacheInputValue, _inputValue, StringComparison.Ordinal)
                && _filterCacheAllowDup == AllowDuplicates)
            {
                return _filteredSuggestionsCache;
            }

            _filterCacheSuggestionsRef = Suggestions;
            _filterCacheTagsRef = Tags;
            _filterCacheInputValue = _inputValue;
            _filterCacheAllowDup = AllowDuplicates;

            if (Suggestions is null || string.IsNullOrWhiteSpace(_inputValue))
            {
                _filteredSuggestionsCache = [];
                return _filteredSuggestionsCache;
            }

            var tags = Tags ?? [];
            _filteredSuggestionsCache = Suggestions
                .Where(s => GetSuggestionTextSafe(s).Contains(_inputValue, StringComparison.OrdinalIgnoreCase)
                            && (AllowDuplicates || !tags.Any(t => EqualityComparer<TItem>.Default.Equals(t, s))))
                .Take(8)
                .ToList();
            return _filteredSuggestionsCache;
        }
    }

    private async Task OnInput(ChangeEventArgs e)
    {
        _inputValue = e.Value?.ToString() ?? "";
        _validationError = null;
        // The filtered set changes on every keystroke, so the previous highlight
        // is meaningless — reset to "no active option".
        _activeSuggestion = -1;

        // Multi-separator splitting on every input event so paste handling works.
        if (Separators is { Length: > 0 } && Separators.Any(sep => !string.IsNullOrEmpty(sep) && _inputValue.Contains(sep)))
        {
            var parts = _inputValue.Split(Separators, StringSplitOptions.RemoveEmptyEntries);
            foreach (var raw in parts)
            {
                var part = raw.Trim();
                if (string.IsNullOrEmpty(part)) continue;
                await TryAddFreeText(part);
            }
            _inputValue = "";
        }

        _showSuggestions = FilteredSuggestions.Count > 0;
    }

    private async Task OnKeyDown(KeyboardEventArgs e)
    {
        var suggestions = FilteredSuggestions;

        switch (e.Key)
        {
            case "ArrowDown":
                if (suggestions.Count == 0) break;
                // Open the list (if it was closed) and move the highlight down,
                // wrapping back to the top after the last row.
                _showSuggestions = true;
                _activeSuggestion = _activeSuggestion < 0 || _activeSuggestion >= suggestions.Count - 1
                    ? 0
                    : _activeSuggestion + 1;
                break;
            case "ArrowUp":
                if (suggestions.Count == 0) break;
                _showSuggestions = true;
                _activeSuggestion = _activeSuggestion <= 0
                    ? suggestions.Count - 1
                    : _activeSuggestion - 1;
                break;
            case "Enter":
                // A highlighted suggestion wins over free-text entry, matching the
                // combobox contract (Down then Enter picks that row).
                if (_showSuggestions && _activeSuggestion >= 0 && _activeSuggestion < suggestions.Count)
                {
                    await SelectSuggestion(suggestions[_activeSuggestion]);
                }
                else if (!string.IsNullOrWhiteSpace(_inputValue))
                {
                    await TryAddFreeText(_inputValue.Trim());
                    if (_validationError is null)
                    {
                        _inputValue = "";
                        _showSuggestions = false;
                    }
                }
                break;
            case "Backspace":
                if (string.IsNullOrEmpty(_inputValue) && Tags is { Count: > 0 })
                {
                    await RemoveTagAt(Tags.Count - 1);
                }
                break;
            case "Escape":
                _showSuggestions = false;
                _activeSuggestion = -1;
                break;
        }
    }

    private async Task TryAddFreeText(string text)
    {
        if (string.IsNullOrWhiteSpace(text)) return;

        // Sync validation
        if (ValidateInput is not null)
        {
            var err = ValidateInput(text);
            if (err is not null)
            {
                _validationError = err;
                return;
            }
        }

        // Async validation
        if (ValidateInputAsync is not null)
        {
            var err = await ValidateInputAsync(text);
            if (err is not null)
            {
                _validationError = err;
                return;
            }
        }

        // Match existing suggestion (use suggestion text for comparison)
        if (Suggestions is not null)
        {
            foreach (var s in Suggestions)
            {
                if (string.Equals(GetSuggestionTextSafe(s), text, StringComparison.OrdinalIgnoreCase))
                {
                    await AddTag(s);
                    return;
                }
            }
        }

        // Convert free text → TItem
        TItem created;
        if (CreateTag is not null)
        {
            var maybe = CreateTag(text);
            if (maybe is null) return;
            created = maybe;
        }
        else if (typeof(TItem) == typeof(string))
        {
            created = (TItem)(object)text;
        }
        else
        {
            throw new InvalidOperationException(
                "Free-text input requires CreateTag callback for non-string TItem");
        }

        await AddTag(created);
    }

    private async Task AddTag(TItem tag)
    {
        if (IsAtMax) return;

        Tags ??= [];
        if (!AllowDuplicates && Tags.Any(t => EqualityComparer<TItem>.Default.Equals(t, tag))) return;

        Tags = [..Tags, tag];
        _validationError = null;
        await TagsChanged.InvokeAsync(Tags);
    }

    // Remove a single tag by position. Keying removal on the index (rather than
    // value-equality) means duplicate tags are removed one occurrence at a time —
    // a value-equality Where(...) would strip EVERY equal tag when AllowDuplicates
    // is true. The index comes from the render loop, so it is always in range for
    // the list that produced the chip; the bounds guard is defensive only.
    private async Task RemoveTagAt(int index)
    {
        if (Tags is null || index < 0 || index >= Tags.Count) return;
        Tags = Tags.Where((_, i) => i != index).ToList();
        await TagsChanged.InvokeAsync(Tags);
    }

    private async Task SelectSuggestion(TItem suggestion)
    {
        await AddTag(suggestion);
        _inputValue = "";
        _showSuggestions = false;
        _activeSuggestion = -1;
        await Interop.FocusElement(EffectiveId);
    }

    private async Task FocusInput()
    {
        if (!Disabled) await Interop.FocusElement(EffectiveId);
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            // Enter must add a tag, not submit an enclosing <form>; ArrowUp/Down
            // must drive the suggestions listbox (combobox contract), not jump the
            // text caret to start/end. A native JS listener is the only race-free
            // way to suppress the browser default for the current event (Blazor's
            // :preventDefault flag is applied at render time). SkipComposing keeps
            // IME composition commits (isComposing / keyCode 229) working.
            try
            {
                await Interop.RegisterPreventDefaultKeys(EffectiveId, new[]
                {
                    new Lumeo.Services.PreventDefaultKeyRule("Enter", SkipComposing: true),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowDown"),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowUp"),
                });
                _pdRegistered = true;
            }
            catch (JSDisconnectedException) { }
            catch (JSException) { /* element may not exist (prerender teardown) */ }
            catch (InvalidOperationException) { } // JS interop unavailable during prerender
        }
        if (firstRender && AutoFocus)
        {
            try { await Interop.FocusElement(EffectiveId); }
            catch (JSDisconnectedException) { }
        }
        if (_showSuggestions && !_suggestionsRegistered)
        {
            try
            {
                await Interop.PositionFixed(_suggestionsId, EffectiveId, "start", false, "bottom");
                await Interop.RegisterClickOutside(_suggestionsId, EffectiveId, async () =>
                {
                    _showSuggestions = false;
                    await InvokeAsync(StateHasChanged);
                });
                _suggestionsRegistered = true;
            }
            catch (JSException) { /* element may not exist yet */ }
        }
        else if (!_showSuggestions && _suggestionsRegistered)
        {
            await CleanupSuggestions();
        }
    }

    private async Task CleanupSuggestions()
    {
        try { await Interop.UnpositionFixed(_suggestionsId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(_suggestionsId); } catch (JSDisconnectedException) { }
        _suggestionsRegistered = false;
    }

    // Set only after a successful JS registration — dispose during static
    // prerendering must not import the JS module just to unregister.
    private bool _pdRegistered;

    public async ValueTask DisposeAsync()
    {
        if (_suggestionsRegistered) await CleanupSuggestions();
        if (!_pdRegistered) return;
        try { await Interop.UnregisterPreventDefaultKeys(EffectiveId); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}
